// src/context/FuelContext.jsx
import React, { createContext, useContext, useState } from 'react';

const FuelContext = createContext(null);

export function FuelProvider({ children }) {
  const [livePrices, setLivePrices] = useState({
    Diesel: 87.71,
    Petrol: 96.72,
    loaded: false,
  });

  const updatePrices = (prices) => {
    if (prices && prices.diesel && prices.petrol) {
      setLivePrices({
        Diesel: prices.diesel,
        Petrol: prices.petrol,
        loaded: true,
      });
    }
  };

  return (
    <FuelContext.Provider value={{ livePrices, updatePrices }}>
      {children}
    </FuelContext.Provider>
  );
}

export function useFuelPrices() {
  const context = useContext(FuelContext);
  // ✅ FIX: Return default object instead of null
  if (!context) {
    console.warn('⚠️ useFuelPrices must be used within FuelProvider - using fallback prices');
    return {
      livePrices: { Diesel: 87.71, Petrol: 96.72, loaded: false },
      updatePrices: () => {},
    };
  }
  return context;
}
